def solve(order_number):
    if not order_number:
        return {"error": "Order number is required."}

    # Mockup data for demonstration purposes
    mock_data = {
        "12345": {"devices": ["Device A", "Device B"], "status": "configured"},
        "67890": {"devices": ["Device C"], "status": "pending"},
    }

    return mock_data.get(order_number, {"error": "Order not found."})
